// ═══════════════════════════════════════════════════
// AUDIO SYSTEM
// ═══════════════════════════════════════════════════
let isMuted = false;
let musicVolume = 0.6;
let sfxVolume = 0.8;
let currentMusicId = null;
let currentMusicEl = null;

function setMusicVolume(v) {
  musicVolume = parseFloat(v);
  if (currentMusicEl && !isMuted) currentMusicEl.volume = musicVolume;
}

function setSfxVolume(v) {
  sfxVolume = parseFloat(v);
}

function toggleMute() {
  isMuted = !isMuted;
  const btn = document.getElementById('volBtn');
  btn.textContent = isMuted ? '🔇' : '🔊';
  btn.classList.toggle('muted', isMuted);
  if (currentMusicEl) {
    currentMusicEl.volume = isMuted ? 0 : musicVolume;
  }
}

function playMusic(difficulty) {
  stopMusic();
  const cfg = DIFFICULTY[difficulty];
  if (!cfg) return;
  const el = document.getElementById(cfg.musicId);
  if (!el) return;
  currentMusicId = cfg.musicId;
  currentMusicEl = el;
  el.currentTime = 0;
  el.volume = 0;
  el.play().catch(() => {});
  // fade in
  let v = 0;
  const fadeIn = setInterval(() => {
    v = Math.min(v + 0.03, isMuted ? 0 : musicVolume);
    el.volume = v;
    if (v >= musicVolume || isMuted) clearInterval(fadeIn);
  }, 80);
}

function stopMusic() {
  if (!currentMusicEl) return;
  const el = currentMusicEl;
  let v = el.volume;
  const fadeOut = setInterval(() => {
    v = Math.max(v - 0.05, 0);
    el.volume = v;
    if (v <= 0) { el.pause(); clearInterval(fadeOut); }
  }, 60);
  currentMusicEl = null;
  currentMusicId = null;
}

function playKillSound() {
  if (isMuted) return;
  // Play the embedded kill mp3
  const el = document.getElementById('audio-kill');
  if (el) {
    el.volume = sfxVolume;
    el.currentTime = 0;
    el.play().catch(() => {});
  }
  // Also play the procedural Web Audio chime (v1 style)
  try {
    const ctx = getAudioCtx();
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    const osc2 = ctx.createOscillator();
    const gain2 = ctx.createGain();
    osc.connect(gain); gain.connect(ctx.destination);
    osc2.connect(gain2); gain2.connect(ctx.destination);
    osc.frequency.setValueAtTime(440, t);
    osc.frequency.linearRampToValueAtTime(660, t + 0.08);
    osc.frequency.linearRampToValueAtTime(880, t + 0.15);
    osc.type = 'sine';
    gain.gain.setValueAtTime(sfxVolume * 0.22, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.35);
    osc2.frequency.setValueAtTime(880, t + 0.1);
    osc2.frequency.linearRampToValueAtTime(1320, t + 0.25);
    osc2.type = 'triangle';
    gain2.gain.setValueAtTime(sfxVolume * 0.12, t + 0.1);
    gain2.gain.exponentialRampToValueAtTime(0.001, t + 0.4);
    osc.start(t); osc.stop(t + 0.4);
    osc2.start(t + 0.1); osc2.stop(t + 0.4);
  } catch(e) {}
}

// Web Audio for fail sound (keep procedural)
const AudioCtx = window.AudioContext || window.webkitAudioContext;
let audioCtx = null;
function getAudioCtx() {
  if (!audioCtx) audioCtx = new AudioCtx();
  return audioCtx;
}

function playFail() {
  if (isMuted) return;
  try {
    const ctx = getAudioCtx();
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    const filter = ctx.createBiquadFilter();
    osc.connect(filter); filter.connect(gain); gain.connect(ctx.destination);
    osc.type = 'sawtooth';
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(600, t);
    filter.frequency.linearRampToValueAtTime(150, t + 0.4);
    osc.frequency.setValueAtTime(180, t);
    osc.frequency.linearRampToValueAtTime(50, t + 0.4);
    gain.gain.setValueAtTime(sfxVolume * 0.4, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.5);
    osc.start(t); osc.stop(t + 0.5);
  } catch(e) {}
}

