let selectedDifficulty = 'easy';

let gameState = {
  active: false,
  paused: false,
  score: 0,
  lives: 3,
  combo: 1,
  maxCombo: 1,
  totalWords: 0,
  successWords: 0,
  attempts: 0,
  words: [],
  spawnTimer: null,
  nextWordId: 0,
  rafId: null,
  difficulty: 'easy',
  milestonesTriggered: new Set(),
};

// ═══════════════════════════════════════════════════
// DIFFICULTY SELECTION
// ═══════════════════════════════════════════════════
function selectDifficulty(diff, btn) {
  selectedDifficulty = diff;
  document.querySelectorAll('.diff-btn').forEach(b => b.classList.remove('selected'));
  btn.classList.add('selected');
}

// ═══════════════════════════════════════════════════
// WORD HELPERS
// ═══════════════════════════════════════════════════
function pickWord() {
  const rand = Math.random();
  let pool;
  
  // Use custom words if loaded, otherwise fallback to default WORDS
  const dictionary = currentCustomWords || WORDS;
  
  if (rand < 0.25) pool = dictionary.short || WORDS.short;
  else if (rand < 0.55) pool = dictionary.medium4 || WORDS.medium4;
  else if (rand < 0.80) pool = dictionary.medium6 || WORDS.medium6;
  else pool = dictionary.long || WORDS.long;
  
  return pool[Math.floor(Math.random() * pool.length)];
}

function getWordDuration(word) {
  const len = word.length;
  const cfg = DIFFICULTY[gameState.difficulty];
  let base;
  if (len <= 3) base = 4.5;
  else if (len <= 5) base = 5.5;
  else if (len <= 8) base = 6.5;
  else base = 7.5;
  const variation = (Math.random() - 0.5);  // ±0.5s
  return (base + variation) * 1000 * cfg.durationMultiplier;
}

function getWordPoints(word) {
  const len = word.length;
  if (len <= 3) return 10;
  if (len <= 5) return 20;
  if (len <= 8) return 30;
  return 50;
}

// ═══════════════════════════════════════════════════
// SPAWN
// ═══════════════════════════════════════════════════
function spawnWord() {
  if (!gameState.active || gameState.paused) return;
  const cfg = DIFFICULTY[gameState.difficulty];
  const activeCount = gameState.words.filter(w => !w.removed).length;
  if (activeCount >= cfg.maxWords) return;

  const arena = document.getElementById('arena');
  const arenaW = arena.clientWidth;

  const text = pickWord();
  const duration = getWordDuration(text);
  const points = getWordPoints(text);

  const el = document.createElement('div');
  el.className = 'word-tile';
  el.textContent = text;

  let x;
  let tries = 0;
  do {
    x = Math.floor(Math.random() * (arenaW - 180)) + 10;
    tries++;
  } while (tries < 20 && gameState.words.some(w => Math.abs(w.x - x) < 100 && (performance.now() - w.startTime) < 1000));

  el.style.left = x + 'px';
  el.style.top = '-40px';
  arena.appendChild(el);

  const id = gameState.nextWordId++;
  const word = { id, text, el, x, startTime: performance.now(), duration, points, removed: false };
  gameState.words.push(word);
  gameState.totalWords++;
}

// ═══════════════════════════════════════════════════
// GAME LOOP
// ═══════════════════════════════════════════════════
function gameLoop(ts) {
  if (!gameState.active) return;
  if (gameState.paused) {
    gameState.rafId = requestAnimationFrame(gameLoop);
    return;
  }

  const arena = document.getElementById('arena');
  const arenaH = arena.clientHeight;
  const now = performance.now();
  let missed = [];

  for (const word of gameState.words) {
    if (word.removed) continue;
    const progress = (now - word.startTime) / word.duration;
    const y = -40 + progress * (arenaH + 40);
    word.el.style.top = y + 'px';
    if (y >= arenaH) {
      console.log('WORD MISSED:', word.text, 'y:', y, 'arenaH:', arenaH, 'progress:', progress, 'duration:', word.duration, 'now:', now, 'startTime:', word.startTime);
      missed.push(word);
    }
  }

  for (const word of missed) wordMissed(word);

  // highlight
  const inputVal = document.getElementById('wordInput').value.trim().toUpperCase();
  for (const word of gameState.words) {
    if (word.removed) continue;
    if (inputVal && word.text.startsWith(inputVal)) word.el.classList.add('highlighted');
    else word.el.classList.remove('highlighted');
  }

  gameState.rafId = requestAnimationFrame(gameLoop);
}

// ═══════════════════════════════════════════════════
// WORD MISSED
// ═══════════════════════════════════════════════════
function wordMissed(word) {
  word.removed = true;
  word.el.remove();
  gameState.words = gameState.words.filter(w => w.id !== word.id);
  gameState.lives--;
  gameState.combo = 1;
  playFail();
  updateHUD();
  shakeArena();
  if (gameState.lives <= 0) endGame();
}

// ═══════════════════════════════════════════════════
// MILESTONE SYSTEM
// ═══════════════════════════════════════════════════
function checkMilestones(score) {
  for (const m of MILESTONES) {
    if (score >= m.score && !gameState.milestonesTriggered.has(m.score)) {
      gameState.milestonesTriggered.add(m.score);
      triggerMilestone(m);
      break;
    }
  }
}

function triggerMilestone(m) {
  // pause gameplay
  gameState.paused = true;

  const overlay = document.getElementById('milestoneOverlay');
  const breakOverlay = document.getElementById('breakOverlay');
  const textEl = document.getElementById('milestoneText');
  const subEl = document.getElementById('milestoneSub');
  const countdownEl = document.getElementById('milestoneCountdown');
  const inner = document.getElementById('milestoneInner');

  textEl.textContent = m.text;
  subEl.textContent = m.sub;
  overlay.classList.add('show');
  breakOverlay.classList.add('show');
  inner.style.animation = 'none';
  void inner.offsetWidth;
  inner.style.animation = 'milestoneAnim 0.6s cubic-bezier(0.16, 1, 0.3, 1) both';

  // countdown
  let remaining = Math.ceil(m.pauseMs / 1000);
  countdownEl.textContent = '— BREAK: ' + remaining + 's —';
  const countTimer = setInterval(() => {
    remaining--;
    if (remaining > 0) countdownEl.textContent = '— BREAK: ' + remaining + 's —';
    else { countdownEl.textContent = '— RESUMING —'; clearInterval(countTimer); }
  }, 1000);

  setTimeout(() => {
    inner.style.animation = 'milestoneFade 0.5s ease forwards';
    setTimeout(() => {
      overlay.classList.remove('show');
      breakOverlay.classList.remove('show');
      gameState.paused = false;
      // reset word timers so they don't instantly hit bottom
      const offset = m.pauseMs;
      for (const word of gameState.words) {
        if (!word.removed) word.startTime += offset;
      }
      document.getElementById('wordInput').focus();
    }, 500);
  }, m.pauseMs);
}

