// ═══════════════════════════════════════════════════
document.getElementById('wordInput').addEventListener('keydown', (e) => {
  if (e.key === 'Enter') { e.preventDefault(); submitWord(); }
});

document.getElementById('wordInput').addEventListener('input', () => {
  if (audioCtx && audioCtx.state === 'suspended') audioCtx.resume();
});

function submitWord() {
  if (!gameState.active || gameState.paused) return;
  const input = document.getElementById('wordInput');
  const typed = input.value.trim().toUpperCase();
  if (!typed) return;

  gameState.attempts++;
  const match = gameState.words.find(w => !w.removed && w.text === typed);

  if (match) {
    match.removed = true;
    gameState.words = gameState.words.filter(w => w.id !== match.id);
    gameState.successWords++;

    const pts = match.points * gameState.combo;
    gameState.score += pts;
    gameState.combo = Math.min(gameState.combo + 1, 8);
    if (gameState.combo > gameState.maxCombo) gameState.maxCombo = gameState.combo;

    match.el.classList.add('success-anim');
    setTimeout(() => match.el.remove(), 400);

    showScorePopup(match.el, '+' + pts);
    playKillSound();
    flashScore();
    input.value = '';

    checkMilestones(gameState.score);
  } else {
    input.classList.add('wrong-flash');
    setTimeout(() => input.classList.remove('wrong-flash'), 300);
    gameState.combo = 1;
  }

  updateHUD();
}

function showScorePopup(ref, text) {
  const arena = document.getElementById('arena');
  const rect = ref.getBoundingClientRect();
  const arenaRect = arena.getBoundingClientRect();
  const popup = document.createElement('div');
  popup.className = 'score-popup';
  popup.textContent = text;
  popup.style.left = (rect.left - arenaRect.left + rect.width / 2 - 30) + 'px';
  popup.style.top = (rect.top - arenaRect.top) + 'px';
  arena.appendChild(popup);
  setTimeout(() => popup.remove(), 900);
}

// ═══════════════════════════════════════════════════
// HUD
// ═══════════════════════════════════════════════════
function updateHUD() {
  document.getElementById('scoreDisplay').textContent = gameState.score;
  document.getElementById('comboDisplay').textContent = 'x' + gameState.combo;
  const acc = gameState.attempts > 0
    ? Math.round((gameState.successWords / gameState.attempts) * 100) : '--';
  document.getElementById('accuracyDisplay').textContent = acc + (acc === '--' ? '' : '%');
  const lifeEls = document.querySelectorAll('.life-icon');
  lifeEls.forEach((el, i) => el.classList.toggle('lost', i >= gameState.lives));
}

function flashScore() {
  const el = document.getElementById('scoreDisplay');
  el.classList.add('flash');
  setTimeout(() => el.classList.remove('flash'), 200);
}

function shakeArena() {
  const arena = document.getElementById('arena');
  arena.classList.remove('shake');
  void arena.offsetWidth;
  arena.classList.add('shake');
  setTimeout(() => arena.classList.remove('shake'), 400);
}

// ═══════════════════════════════════════════════════
// START / END GAME
// ═══════════════════════════════════════════════════
function startGame() {
  const diff = selectedDifficulty;
  const cfg = DIFFICULTY[diff];
  
  // Hide difficulty selection menu
  document.getElementById('difficultyOptions').style.display = 'none';
  
  // Check for custom theme
  const themeId = document.getElementById('themeSelect').value;
  if(themeId !== 'default') {
      fetch(`/api/wordlists/${themeId}`)
        .then(res => res.json())
        .then(data => {
            if(data.words) {
                currentCustomWords = data.words;
                initGameSequence(diff, cfg); // proceed after loading theme
            } else {
                currentCustomWords = null;
                initGameSequence(diff, cfg);
            }
        })
        .catch(err => {
            console.error('Failed to load theme:', err);
            currentCustomWords = null;
            initGameSequence(diff, cfg);
        });
  } else {
      currentCustomWords = null;
      initGameSequence(diff, cfg);
  }
}

function initGameSequence(diff, cfg) {
  // ── Start music NOW while we still have a direct user gesture ──
  if (!audioCtx) audioCtx = new AudioCtx();
  if (audioCtx.state === 'suspended') audioCtx.resume();
  playMusic(diff);

  showPage('game');

  // Update diff badge
  const badge = document.getElementById('diffBadge');
  badge.textContent = cfg.label;
  badge.className = 'diff-badge ' + diff;

  gameState = {
    active: false,   // held false until splash gone
    paused: false,
    score: 0,
    lives: 3,
    combo: 1,
    maxCombo: 1,
    totalWords: 0,
    successWords: 0,
    attempts: 0,
    words: [],
    spawnTimer: null,
    nextWordId: 0,
    rafId: null,
    difficulty: diff,
    milestonesTriggered: new Set(),
    startTime: 0,
  };

  const arena = document.getElementById('arena');
  arena.querySelectorAll('.word-tile').forEach(el => el.remove());
  document.getElementById('wordInput').value = '';
  document.getElementById('gameOverOverlay').classList.remove('active');
  document.getElementById('milestoneOverlay').classList.remove('show');
  document.getElementById('breakOverlay').classList.remove('show');

  updateHUD();

  // Show mode entry splash
  const taglines = { easy: 'STAY CALM. TYPE STEADY.', median: 'PACE YOURSELF.', hard: 'DO NOT BLINK.' };
  document.getElementById('splashName').textContent = cfg.label;
  document.getElementById('splashName').className = 'splash-mode-name ' + diff;
  document.getElementById('splashLabel').style.color = { easy:'#a5d6a7', median:'#ffcc80', hard:'#ffcdd2' }[diff];
  document.getElementById('splashTagline').textContent = taglines[diff];
  const splash = document.getElementById('modeSplash');
  const splashInner = document.getElementById('splashInner');
  splash.classList.add('show');
  splashInner.style.animation = 'none';
  void splashInner.offsetWidth;
  splashInner.style.animation = 'splashIn 0.5s cubic-bezier(0.16,1,0.3,1) both';

  setTimeout(() => {
    splashInner.style.animation = 'splashOut 0.4s ease forwards';
    setTimeout(() => {
      splash.classList.remove('show');

      // NOW activate the game
      gameState.active = true;
      gameState.startTime = Date.now();
      gameState.rafId = requestAnimationFrame(gameLoop);

      for (let i = 0; i < cfg.initialWords; i++) {
        setTimeout(() => spawnWord(), i * 600);
      }

      gameState.spawnTimer = setInterval(() => {
        if (gameState.paused) return;
        const activeCount = gameState.words.filter(w => !w.removed).length;
        const deficit = Math.max(0, cfg.minWords - activeCount);
        const spawns = Math.max(deficit, activeCount < cfg.maxWords ? 1 : 0);
        for (let i = 0; i < spawns; i++) spawnWord();
      }, cfg.spawnInterval);

      document.getElementById('wordInput').focus();
    }, 400);
  }, 2200);
}

function endGame() {
  gameState.active = false;
  clearInterval(gameState.spawnTimer);
  cancelAnimationFrame(gameState.rafId);

  gameState.words.forEach(w => { if (!w.removed) w.el.remove(); });
  gameState.words = [];

  stopMusic();

  const acc = gameState.attempts > 0
    ? Math.round((gameState.successWords / gameState.attempts) * 100) : 0;

  const durationMs = Date.now() - gameState.startTime;
  const durationMins = durationMs / 60000;
  const wpm = (gameState.successWords > 0 && durationMins > 0) ? Math.round(gameState.successWords / durationMins) : 0;
  const wps = (gameState.successWords > 0 && durationMs > 0) ? (gameState.successWords / (durationMs / 1000)).toFixed(2) : 0;

  document.getElementById('goScore').textContent = gameState.score;
  document.getElementById('goAccuracy').textContent = acc + '%';
  document.getElementById('goWords').textContent = gameState.successWords;
  document.getElementById('goCombo').textContent = 'x' + gameState.maxCombo;
  
  if (document.getElementById('goWpm')) {
    document.getElementById('goWpm').textContent = `${wpm} / ${wps}`;
  }
  
  document.getElementById('gameOverOverlay').classList.add('active');

  const wpmAnalyticsDiv = document.getElementById('wpmAnalytics');
  if(wpmAnalyticsDiv) wpmAnalyticsDiv.style.display = 'none';

  // Local Save
  saveHistory(acc);
  
  // Cloud Save
  if (currentUser) {
      // Submit to Leaderboard
      if (gameState.score > 0) {
          fetch('/api/scores', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                  username: currentUser.username,
                  user_id: currentUser.id,
                  score: gameState.score,
                  difficulty: gameState.difficulty,
                  accuracy: acc,
                  max_combo: gameState.maxCombo,
                  wpm: wpm
              })
          }).catch(console.error);
      }
      
      // Update User Stats
      fetch(`/api/users/${currentUser.id}/stats/update`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
              score: gameState.score,
              accuracy: acc,
              total_words: gameState.totalWords,
              success_words: gameState.successWords
          })
      }).catch(console.error);

      // Fetch WPM analytics
      fetch(`/api/users/${currentUser.id}/wpm-stats`)
        .then(res => res.json())
        .then(data => {
            if(!data.error && wpmAnalyticsDiv) {
                wpmAnalyticsDiv.style.display = 'block';
                
                // Compare speed and fetch demographic stats
                // World record (212 WPM) comparison included
                
                wpmAnalyticsDiv.innerHTML = `
                    <div style="margin-bottom: 8px;"><strong>Your Best: ${data.user_max_wpm} WPM</strong></div>
                    <div style="color: rgba(255,255,255,0.7); font-size: 12px; margin-bottom: 4px;">
                        Average WPM: ${data.average_wpm} (Men: ${data.average_male_wpm}, Women: ${data.average_female_wpm})
                    </div>
                    <div style="color: rgba(255,255,255,0.7); font-size: 12px; margin-top: 5px;">
                        World Record: ${data.world_record_wpm} WPM (You: ${data.percentage_of_world_record}%)
                    </div>
                `;
            }
        })
        .catch(console.error);
  }
}

function restartGame() {
  document.getElementById('gameOverOverlay').classList.remove('active');
  if (!audioCtx) audioCtx = new AudioCtx();
  if (audioCtx.state === 'suspended') audioCtx.resume();
  startGame();
}

function goHome() {
  document.getElementById('gameOverOverlay').classList.remove('active');
  document.getElementById('modeSplash').classList.remove('show');
  gameState.active = false;
  clearInterval(gameState.spawnTimer);
  cancelAnimationFrame(gameState.rafId);
  stopMusic();
  showPage('home');
}

// ═══════════════════════════════════════════════════
// HISTORY
// ═══════════════════════════════════════════════════
function saveHistory(accuracy) {
  const raw = localStorage.getItem('vortex_history');
  const hist = raw ? JSON.parse(raw) : {
    gamesPlayed: 0, highScore: 0, totalAccuracy: 0, totalWords: 0, successWords: 0,
  };
  hist.gamesPlayed++;
  if (gameState.score > hist.highScore) hist.highScore = gameState.score;
  hist.totalAccuracy += accuracy;
  hist.totalWords += gameState.totalWords;
  hist.successWords += gameState.successWords;
  localStorage.setItem('vortex_history', JSON.stringify(hist));
}

function clearHistory() {
  const btn = document.querySelector('.btn-danger[onclick="clearHistory()"]');
  if (!btn) return;
  if (btn.dataset.confirming === 'true') {
    localStorage.removeItem('vortex_history');
    btn.textContent = '✓ CLEARED';
    btn.dataset.confirming = 'false';
    btn.style.background = 'linear-gradient(135deg, #1a4a1a, #27ae60)';
    renderHistory();
    setTimeout(() => {
      btn.textContent = '✕ CLEAR';
      btn.style.background = '';
    }, 2000);
  } else {
    btn.dataset.confirming = 'true';
    btn.textContent = '⚠ CONFIRM?';
    btn.style.background = 'linear-gradient(135deg, #7a2000, #e65100)';
    setTimeout(() => {
      if (btn.dataset.confirming === 'true') {
        btn.dataset.confirming = 'false';
        btn.textContent = '✕ CLEAR';
        btn.style.background = '';
      }
    }, 3000);
  }
}

function showHistory() {
  if (currentUser) {
      // Load global stats from API
      fetch(`/api/users/${currentUser.id}/stats`)
        .then(res => res.json())
        .then(data => {
            if(!data.error) renderHistory(data);
            else renderHistory(null);
        })
        .catch(err => renderHistory(null));
  } else {
      // Local stats
      const raw = localStorage.getItem('vortex_history');
      renderHistory(raw ? JSON.parse(raw) : null);
  }
  showPage('history');
}

function renderHistory(h) {
  const container = document.getElementById('historyContent');
  if (!h) {
    container.innerHTML = '<div class="no-history">// NO RECORDS FOUND //<br><br>Complete a game to see your stats.</div>';
    return;
  }
  
  // Normalize response keys from SQLite (snake_case) to camelCase if needed
  const gamesPlayed = h.games_played !== undefined ? h.games_played : h.gamesPlayed;
  const highScore = h.highest_score !== undefined ? h.highest_score : h.highScore;
  const totalAccuracy = h.total_accuracy !== undefined ? h.total_accuracy : h.totalAccuracy;
  const totalWords = h.total_words !== undefined ? h.total_words : h.totalWords;
  const successWords = h.success_words !== undefined ? h.success_words : h.successWords;

  const avgAcc = gamesPlayed > 0 ? Math.round(totalAccuracy / gamesPlayed) : 0;
  const successPct = totalWords > 0 ? Math.round((successWords / totalWords) * 100) : 0;
  container.innerHTML = `
    <div style="text-align:center; margin-bottom:20px; color:#666;">
        ${currentUser ? 'SERVER STATISTICS' : 'LOCAL STATISTICS'}
    </div>
    <div class="stat-grid">
      <div class="stat-card"><div class="stat-label">Games Played</div><div class="stat-value large">${gamesPlayed}</div></div>
      <div class="stat-card"><div class="stat-label">High Score</div><div class="stat-value large">${highScore}</div></div>
      <div class="stat-card"><div class="stat-label">Avg. Accuracy</div><div class="stat-value">${avgAcc}%</div></div>
      <div class="stat-card"><div class="stat-label">Total Words</div><div class="stat-value">${totalWords}</div></div>
      <div class="stat-card"><div class="stat-label">Successful Words</div><div class="stat-value">${successWords}</div></div>
      <div class="stat-card"><div class="stat-label">Success Rate</div><div class="stat-value">${successPct}%</div></div>
    </div>
  `;
}

// ═══════════════════════════════════════════════════
// NEW BACKEND INTEGRATIONS
// ═══════════════════════════════════════════════════

let currentUser = null;
let currentCustomWords = null;

// Initialize session if exists
function checkSession() {
    const raw = localStorage.getItem('vortex_user');
    if (raw) {
        currentUser = JSON.parse(raw);
        document.getElementById('loggedInUser').textContent = currentUser.username;
        document.getElementById('userCard').style.display = 'block';
        document.getElementById('accountBtn').style.display = 'none';
    }
    loadThemes();
}

function showDifficultySelection() {
    document.getElementById('difficultyOptions').style.display = 'block';
}

function loadThemes() {
    fetch('/api/wordlists')
        .then(res => res.json())
        .then(lists => {
            const select = document.getElementById('themeSelect');
            lists.forEach(list => {
                const opt = document.createElement('option');
                opt.value = list.id;
                opt.textContent = list.name;
                select.appendChild(opt);
            });
        })
        .catch(err => console.error("Error loading themes:", err));
}

function handleAuthResponse(res) {
    if(!res.ok) {
        res.json().then(data => document.getElementById('authMsg').textContent = data.error);
        return;
    }
    res.json().then(data => {
        currentUser = data;
        localStorage.setItem('vortex_user', JSON.stringify(data));
        document.getElementById('usernameInput').value = '';
        document.getElementById('passwordInput').value = '';
        document.getElementById('authMsg').textContent = '';
        document.getElementById('loggedInUser').textContent = data.username;
        document.getElementById('userCard').style.display = 'block';
        document.getElementById('accountBtn').style.display = 'none';
        showPage('home');
    });
}

function login() {
    const username = document.getElementById('usernameInput').value.trim();
    const password = document.getElementById('passwordInput').value.trim();
    if(!username || !password) return;
    
    fetch('/api/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({username, password})
    }).then(handleAuthResponse);
}

function register() {
    const username = document.getElementById('usernameInput').value.trim();
    const password = document.getElementById('passwordInput').value.trim();
    if(!username || !password) return;
    
    fetch('/api/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({username, password})
    }).then(handleAuthResponse);
}

function logout() {
    currentUser = null;
    localStorage.removeItem('vortex_user');
    document.getElementById('userCard').style.display = 'none';
    document.getElementById('accountBtn').style.display = 'inline-block';
}

function loadLeaderboard(diff, btn) {
    document.querySelectorAll('#leaderboard .diff-btn').forEach(b => b.classList.remove('selected'));
    btn.classList.add('selected');
    
    document.getElementById('leaderboardContent').innerHTML = '<div class="no-history">// CALCULATING //</div>';
    
    fetch(`/api/leaderboard?difficulty=${diff}`)
        .then(res => res.json())
        .then(data => {
            const container = document.getElementById('leaderboardContent');
            if(data.length === 0) {
                container.innerHTML = '<div class="no-history">// NO SCORES YET //</div>';
                return;
            }
            
            let html = `
                <table style="width:100%; border-collapse:collapse; color:#fff; font-family:'Courier New', monospace; text-align:left;">
                    <tr style="border-bottom: 1px solid #333; color:#666;">
                        <th style="padding:10px;">RANK</th>
                        <th style="padding:10px;">OPERATIVE</th>
                        <th style="padding:10px;text-align:right;">SCORE</th>
                        <th style="padding:10px;text-align:right;">ACC%</th>
                        <th style="padding:10px;text-align:right;">COMBO</th>
                    </tr>
            `;
            
            data.forEach((row, i) => {
                const color = i === 0 ? '#ffcc80' : i === 1 ? '#a5d6a7' : '#90caf9';
                html += `
                    <tr style="border-bottom: 1px solid #1a1a1a;">
                        <td style="padding:10px; color:${color};">#${i+1}</td>
                        <td style="padding:10px; font-weight:bold;">${row.username}</td>
                        <td style="padding:10px; text-align:right; font-size:18px;">${row.score}</td>
                        <td style="padding:10px; text-align:right;">${row.accuracy}%</td>
                        <td style="padding:10px; text-align:right;">x${row.max_combo}</td>
                    </tr>
                `;
            });
            html += `</table>`;
            container.innerHTML = html;
        })
        .catch(err => {
            document.getElementById('leaderboardContent').innerHTML = '<div class="no-history">// CONNECTION ERROR //</div>';
        });
}


// ═══════════════════════════════════════════════════
// NAVIGATION
// ═══════════════════════════════════════════════════
function showPage(id) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.getElementById(id).classList.add('active');
  
  if(id === 'home') {
      showDifficultySelection();
  }
  
  if(id === 'leaderboard') {
      loadLeaderboard('easy', document.querySelector('#leaderboard .diff-btn.easy'));
  }
}

// Call checkSession on load
document.addEventListener('DOMContentLoaded', checkSession);

document.addEventListener('keydown', (e) => {
  if (gameState.active && !gameState.paused && e.target !== document.getElementById('wordInput')) {
    if (e.key.length === 1 && !e.ctrlKey && !e.metaKey) document.getElementById('wordInput').focus();
  }
});

document.addEventListener('click', () => {
  if (!audioCtx) audioCtx = new AudioCtx();
  if (audioCtx.state === 'suspended') audioCtx.resume();
}, { once: false });
